#
# This will:
# - Add the subdirectory at the given path (with an isolated build dir)
# - Include "${dep_path}/include" as a private include directory
# - Link the test executable with the dependency target
#
# ⚠️ This function only runs if BUILD_TESTING is enabled.
# -----------------------------------------------------------------------------
function(require_test_dependency dep_name dep_path)
    # Exit immediately if we're not in a testing build
    if(NOT BUILD_TESTING)
        return()
    endif()

    # Build absolute path to the dependency
    set(dep_abs_path "${ROOT_DIR}/${dep_path}")

    # Create an isolated build directory for this dependency
    set(dep_build_dir "${CMAKE_BINARY_DIR}/_deps/${dep_name}-build")

    # Add the dependency subdirectory (this creates the "${dep_name}" target)
    add_subdirectory("${dep_abs_path}" "${dep_build_dir}")

    # Add the include/ directory to the test executable
    target_include_directories(${test_executable_name} PRIVATE "${dep_abs_path}/include")

    # Link the test executable with the dependency
    target_link_libraries(${test_executable_name} PRIVATE ${dep_name})
endfunction()

